-- 047_import_legacy_guides.sql
-- Importa el dump legacy de guias al esquema actual.
--
-- Notas:
-- 1) El dump original solo trae contenido en espanol.
-- 2) Para no dejar vacios los idiomas EN/PT, este import usa fallback en espanol
--    para summary_en, summary_pt, content_en y content_pt.
-- 3) Las imagenes legacy se normalizan a rutas locales bajo /images/images/.

ALTER TABLE public.guides
  ADD COLUMN IF NOT EXISTS summary_es TEXT,
  ADD COLUMN IF NOT EXISTS summary_en TEXT,
  ADD COLUMN IF NOT EXISTS summary_pt TEXT;

INSERT INTO public.guide_categories (slug, name_es, name_en, name_pt, sort_order) VALUES
  ('world-bosses', 'Jefes del Mundo',  'World Bosses',   'Chefes do Mundo', 1),
  ('events',       'Eventos',          'Events',         'Eventos',         2),
  ('quests',       'Misiones',         'Quests',         'Missões',         3),
  ('systems',      'Sistemas',         'Systems',        'Sistemas',        4),
  ('general',      'Guías Generales',  'General Guides', 'Guias Gerais',    5)
ON CONFLICT (slug) DO NOTHING;

